5	/**
6	 * Handle one webhook delivery. Returns the HTTP status the endpoint
7	 * should respond with; the gateway retries anything that is not 200.
8	 */
9	function handle_webhook(string $rawBody, array $headers, string $secret): int
10	{
11	    $signature = $headers['X-Signature'] ?? '';
12	    if (!verify($rawBody, $signature, $secret)) {
13	        return 401;
14	    }
15	
16	    $event = json_decode($rawBody, true);
17	    if (!is_array($event) || !isset($event['id'])) {
18	        return 400;
19	    }
20	
21	    $line = date('c') . ' ' . $event['id'] . "\n";
22	    file_put_contents(__DIR__ . '/../events.log', $line, FILE_APPEND | LOCK_EX);
23	
24	    return 200;
25	}
